    ctx.fillStyle = skin;
    // Left arm
    ctx.fillRect(-bodyW / 2 - armW, bodyY + 2, armW, armH);
    // Right arm
    ctx.fillRect(bodyW / 2, bodyY + 2, armW, armH);

    ctx.restore();
  }
}

