/**
 * player.js — Mario: movement, jumping, gravity, tile collision
 */

const GRAVITY = 0.6;
const MAX_FALL = 12;
const MOVE_SPEED = 3.2;
const JUMP_FORCE = -13.5;
const GROUND_ROW = 13;

class Player {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.w = TILE * 0.9;
    this.h = TILE * 0.9;
    this.vx = 0;
    this.vy = 0;
    this.onGround = false;
    this.facing = 1; // 1 = right, -1 = left
    this.alive = true;
    this.invincible = 0; // frames of invincibility
    this.big = false;    // grew from mushroom
    this.runFrame = 0;
    this.runTimer = 0;
  }

  get cx() { return this.x + this.w / 2; }
  get cy() { return this.y + this.h / 2; }

  update(map, dt) {
    if (!this.alive) return;

    // Invincibility countdown
    if (this.invincible > 0) this.invincible -= dt;

    // ── Horizontal movement ──
    let targetVx = 0;
    if (Input.get('ArrowLeft') || Input.get('KeyA')) {
      targetVx = -MOVE_SPEED;
      this.facing = -1;
    }
    if (Input.get('ArrowRight') || Input.get('KeyD')) {
      targetVx = MOVE_SPEED;
      this.facing = 1;
    }

    // Acceleration / deceleration
    if (targetVx !== 0) {
      this.vx += (targetVx - this.vx) * 0.3;
      this.runTimer += dt;
      if (this.runTimer > 6) {
        this.runTimer = 0;
        this.runFrame = (this.runFrame + 1) % 2;
      }
    } else {
      this.vx *= 0.75;
      if (Math.abs(this.vx) < 0.1) this.vx = 0;
      this.runFrame = 0;
    }

    // ── Jump ──
    if ((Input.once('Space') || Input.once('ArrowUp') || Input.once('KeyW')) && this.onGround) {
      this.vy = JUMP_FORCE;
      this.onGround = false;
      if (typeof Sound !== 'undefined') Sound.play('jump');
    }

    // Variable jump height (release to fall faster)
    if (!Input.get('Space') && !Input.get('ArrowUp') && !Input.get('KeyW') && this.vy < -3) {
      this.vy *= 0.9;
    }

    // ── Gravity ──
    this.vy += GRAVITY;
    if (this.vy > MAX_FALL) this.vy = MAX_FALL;

    // ── Move X + collide ──
    this.x += this.vx;
    this.collideX(map);

    // Clamp to world left edge
    if (this.x < 0) this.x = 0;

    // ── Move Y + collide ──
    this.y += this.vy;
    this.onGround = false;
    const hit = this.collideY(map);

    // Fall into pit
    if (this.y > WORLD_H + 32) {
      this.die();
    }

    return hit; // block hit from below
  }

  collideX(map) {
    const left = Math.floor(this.x / TILE);
    const right = Math.floor((this.x + this.w - 0.5) / TILE);
    const top = Math.floor(this.y / TILE);
    const bottom = Math.floor((this.y + this.h - 0.5) / TILE);

    for (let r = top; r <= bottom; r++) {
      for (let c = left; c <= right; c++) {
        const tile = getTile(map, c * TILE, r * TILE);
        if (SOLID.has(tile)) {
          if (this.vx > 0) {
            this.x = c * TILE - this.w;
            this.vx = 0;
          } else if (this.vx < 0) {
            this.x = (c + 1) * TILE;
            this.vx = 0;
          }
          return;
        }
      }
    }
  }

  collideY(map) {
    const left = Math.floor(this.x / TILE);
    const right = Math.floor((this.x + this.w - 0.5) / TILE);
    const top = Math.floor(this.y / TILE);
    const bottom = Math.floor((this.y + this.h - 0.5) / TILE);

    for (let r = top; r <= bottom; r++) {
      for (let c = left; c <= right; c++) {
        const tile = getTile(map, c * TILE, r * TILE);
        if (SOLID.has(tile)) {
          if (this.vy > 0) {
            // Landing on top
            this.y = r * TILE - this.h;
            this.vy = 0;
            this.onGround = true;
          } else if (this.vy < 0) {
            // Hitting block from below
            this.y = (r + 1) * TILE;
            this.vy = 1;
            // Hit block event
            return { col: c, row: r, tile };
          }
          return null;
        }
      }
    }
    return null;
  }

  die() {
    if (this.invincible > 0) return;
    this.alive = false;
  }

  hit() {
    if (this.invincible > 0) return;
    if (this.big) {
      this.big = false;
      this.h = TILE * 0.9;
      this.invincible = 90;
    } else {
      this.die();
    }
  }

  grow() {
    if (!this.big) {
      this.big = true;
      this.h = TILE * 1.3;
    }
  }

  draw(ctx) {
    if (!this.alive) return;
    const sx = this.x - Camera.x;
    const sy = this.y - Camera.y;
    const w = this.w;
    const h = this.h;

    // Invincibility flicker
    if (this.invincible > 0 && Math.floor(this.invincible / 3) % 2 === 0) return;

    ctx.save();

    // Flip for direction
    const cx = sx + w / 2;
    const cy = sy + h / 2;
    ctx.translate(cx, cy);
    ctx.scale(this.facing, 1);

    const big = this.big;
